import{_ as s,o as t,c as a,ag as i}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Wiki-Query Marp Slides Extension — Implementation Plan","description":"","frontmatter":{},"headers":[],"relativePath":"docs/superpowers/plans/2026-04-09-wiki-query-marp-slides.md","filePath":"docs/superpowers/plans/2026-04-09-wiki-query-marp-slides.md"}'),n={name:"docs/superpowers/plans/2026-04-09-wiki-query-marp-slides.md"};function r(l,e,d,o,p,c){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="wiki-query-marp-slides-extension-—-implementation-plan" tabindex="-1">Wiki-Query Marp Slides Extension — Implementation Plan <a class="header-anchor" href="#wiki-query-marp-slides-extension-—-implementation-plan" aria-label="Permalink to &quot;Wiki-Query Marp Slides Extension — Implementation Plan&quot;">​</a></h1><blockquote><p><strong>For agentic workers:</strong> REQUIRED SUB-SKILL: Use superpowers:subagent-driven-development (recommended) or superpowers:executing-plans to implement this plan task-by-task. Steps use checkbox (<code>- [ ]</code>) syntax for tracking.</p></blockquote><p><strong>Goal:</strong> Extend the <code>wiki-query</code> command so that every query automatically generates a Marp slide deck in <code>rxjs-wiki/slides/</code> alongside the filed wiki page.</p><p><strong>Architecture:</strong> One file changes — <code>~/.claude/commands/wiki-query.md</code>. The updated instruction text appends slide-generation steps after the existing log.md step. Slides live in a flat <code>rxjs-wiki/slides/</code> directory; the filename is derived by flattening the wiki page path (<code>core/Observable.md</code> → <code>slides/core-Observable.md</code>).</p><p><strong>Tech Stack:</strong> Marp (markdown slides), plain <code>.md</code> files, no build step.</p><hr><h2 id="file-map" tabindex="-1">File Map <a class="header-anchor" href="#file-map" aria-label="Permalink to &quot;File Map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>File</th></tr></thead><tbody><tr><td>Modify</td><td><code>C:/Users/HP/.claude/commands/wiki-query.md</code></td></tr><tr><td>Created by command at runtime</td><td><code>C:/Users/HP/Web/Frontend/rxjs/rxjs-wiki/slides/&lt;topic&gt;.md</code></td></tr></tbody></table><hr><h2 id="task-1-update-wiki-query-md-with-slide-generation-instructions" tabindex="-1">Task 1: Update wiki-query.md with slide-generation instructions <a class="header-anchor" href="#task-1-update-wiki-query-md-with-slide-generation-instructions" aria-label="Permalink to &quot;Task 1: Update wiki-query.md with slide-generation instructions&quot;">​</a></h2><p><strong>Files:</strong></p><ul><li><p>Modify: <code>C:/Users/HP/.claude/commands/wiki-query.md</code></p></li><li><p>[ ] <strong>Step 1: Read the current file</strong></p><p>Open <code>C:/Users/HP/.claude/commands/wiki-query.md</code> and confirm it contains exactly this single-paragraph text (no trailing newline check needed — just confirm the content):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Answer a question against the RxJS wiki at C:/Users/HP/Web/Frontend/rxjs/rxjs-wiki/. Read index.md first to identify relevant pages, then read those pages and synthesize a thorough answer with [[page]] citations. After answering, always file the answer as a new wiki page automatically — choose the most appropriate folder (core/, history/, patterns/, architectures/, testing/, debugging/), create the page with proper YAML frontmatter (title, category, tags, related, sources, updated), add cross-links to and from related existing pages, add it to index.md, update the .vitepress/config.ts sidebar, and append a &quot;## [YYYY-MM-DD] query | &lt;question summary&gt;&quot; entry to log.md noting the page it was filed as. Follow project code style: tabs, single quotes, $ suffix for Observables, explicit TypeScript types, pipe() over chaining.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>[ ] <strong>Step 2: Overwrite the file with the extended instruction</strong></p><p>Replace the entire file content with:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Answer a question against the RxJS wiki at C:/Users/HP/Web/Frontend/rxjs/rxjs-wiki/. Read index.md first to identify relevant pages, then read those pages and synthesize a thorough answer with [[page]] citations. After answering, always file the answer as a new wiki page automatically — choose the most appropriate folder (core/, history/, patterns/, architectures/, testing/, debugging/), create the page with proper YAML frontmatter (title, category, tags, related, sources, updated), add cross-links to and from related existing pages, add it to index.md, update the .vitepress/config.ts sidebar, and append a &quot;## [YYYY-MM-DD] query | &lt;question summary&gt;&quot; entry to log.md noting the page it was filed as.</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>After appending to log.md, generate a Marp slide deck from the filed page:</span></span>\n<span class="line"><span>1. Derive the slide path: take the filed page path (e.g. `core/Observable.md`), replace `/` with `-`, and prefix with `slides/` → `slides/core-Observable.md`.</span></span>\n<span class="line"><span>2. Create the `slides/` directory inside the wiki root if it does not exist.</span></span>\n<span class="line"><span>3. Write the slide file with this structure:</span></span>\n<span class="line"><span>   - Frontmatter block: `marp: true`, `theme: uncover`, `title` copied from the page&#39;s YAML frontmatter.</span></span>\n<span class="line"><span>   - Title slide: `# &lt;title&gt;` followed by `&gt; &lt;one-sentence summary&gt;` (the `&gt;` blockquote from the top of the filed page).</span></span>\n<span class="line"><span>   - One `---`-separated slide per H2 section from the filed page. For each H2:</span></span>\n<span class="line"><span>     - Use the H2 heading as the slide heading.</span></span>\n<span class="line"><span>     - Condense prose paragraphs to 3–5 tight bullet points.</span></span>\n<span class="line"><span>     - Preserve code blocks; trim any block longer than 15 lines to the most illustrative lines with a `// ...` comment marking the cut.</span></span>\n<span class="line"><span>     - Keep ASCII marble diagrams exactly as-is.</span></span>\n<span class="line"><span>     - Omit the &quot;Related&quot; section entirely.</span></span>\n<span class="line"><span>4. Append `Slides: slides/&lt;filename&gt;` to the existing log.md entry for this query (on the line after &quot;Answer filed as: ...&quot;).</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Follow project code style: tabs, single quotes, $ suffix for Observables, explicit TypeScript types, pipe() over chaining.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div></li><li><p>[ ] <strong>Step 3: Verify the file</strong></p><p>Read <code>wiki-query.md</code> back and confirm:</p><ul><li>The original paragraph is still present unchanged at the top</li><li>The &quot;After appending to log.md, generate a Marp slide deck...&quot; block follows it</li><li>The four numbered steps (derive path, create dir, write file, append log) are all present</li><li>The file ends with the code-style line</li></ul></li><li><p>[ ] <strong>Step 4: Commit</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:/Users/HP/.claude/commands/wiki-query.md</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;feat: extend wiki-query to generate Marp slides after each query&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li></ul><hr><h2 id="task-2-smoke-test-the-updated-command" tabindex="-1">Task 2: Smoke-test the updated command <a class="header-anchor" href="#task-2-smoke-test-the-updated-command" aria-label="Permalink to &quot;Task 2: Smoke-test the updated command&quot;">​</a></h2><p><strong>Files:</strong></p><ul><li>Verify created: <code>C:/Users/HP/Web/Frontend/rxjs/rxjs-wiki/slides/&lt;topic&gt;.md</code></li></ul><p>This task verifies the updated command actually produces a well-formed Marp file. Run a real wiki-query on a simple, already-indexed topic so you can compare the output against the spec without doing deep research.</p><ul><li><p>[ ] <strong>Step 1: Run a wiki-query on an existing topic</strong></p><p>Use the updated <code>/wiki-query</code> command with this prompt:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>What is a BehaviorSubject?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Expected: the command answers the question, files (or skips filing if the page already exists — in that case it should still generate slides from the existing page), and produces a slide file.</p></li><li><p>[ ] <strong>Step 2: Locate the generated slide file</strong></p><p>The filed page will be <code>core/BehaviorSubject.md</code> (already exists in the wiki). The slide file should be at:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:/Users/HP/Web/Frontend/rxjs/rxjs-wiki/slides/core-BehaviorSubject.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Read the file and confirm it is present.</p></li><li><p>[ ] <strong>Step 3: Verify slide file structure</strong></p><p>Check the file for all of the following — each is a pass/fail:</p><table tabindex="0"><thead><tr><th>Check</th><th>Expected</th></tr></thead><tbody><tr><td>First 3 lines</td><td><code>---</code>, <code>marp: true</code>, <code>theme: uncover</code></td></tr><tr><td><code>title:</code> line</td><td>Matches the <code>title:</code> in <code>core/BehaviorSubject.md</code> frontmatter</td></tr><tr><td>Title slide</td><td>Contains <code># BehaviorSubject</code> and a <code>&gt;</code> blockquote line</td></tr><tr><td>Slide breaks</td><td>At least 3 <code>---</code> separators (one per H2 in the source page)</td></tr><tr><td>No &quot;Related&quot; slide</td><td>The word &quot;Related&quot; does not appear as a heading</td></tr><tr><td>Code blocks</td><td>Any code block present is ≤ 15 lines</td></tr></tbody></table><p>If any check fails, note which one and fix the command text in Task 1 Step 2 accordingly, then re-run.</p></li><li><p>[ ] <strong>Step 4: Verify log.md entry</strong></p><p>Open <code>C:/Users/HP/Web/Frontend/rxjs/rxjs-wiki/log.md</code> and find the most recent entry. Confirm it contains both:</p><ul><li><code>Answer filed as: core/BehaviorSubject.md</code> (or similar)</li><li><code>Slides: slides/core-BehaviorSubject.md</code></li></ul></li><li><p>[ ] <strong>Step 5: Commit the generated slide</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:/Users/HP/Web/Frontend/rxjs/rxjs-wiki</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slides/core-BehaviorSubject.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log.md</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;test: add smoke-test slide for BehaviorSubject query&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li></ul><hr><h2 id="self-review-notes" tabindex="-1">Self-Review Notes <a class="header-anchor" href="#self-review-notes" aria-label="Permalink to &quot;Self-Review Notes&quot;">​</a></h2><ul><li>Spec requires: automatic generation on every query → Task 1 adds it to the command; Task 2 verifies it fires</li><li>Spec requires: flat <code>slides/</code> dir → path-flattening rule in Step 2 covers this</li><li>Spec requires: <code>uncover</code> theme → frontmatter in Step 2 specifies it</li><li>Spec requires: one slide per H2 → rule 3 in the instruction covers this</li><li>Spec requires: log entry extended → rule 4 in the instruction covers this</li><li>No placeholders or TBDs in any step</li></ul>',21)])])}const m=s(n,[["render",r]]);export{u as __pageData,m as default};
